import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import './MyPetProfile.css';
import axios from 'axios';

function MyPetEditPage() {
    const { petId } = useParams();
    const navigate = useNavigate();

    const [petData, setPetData] = useState({
        name: '',
        type: '',
        weight: '',
        age: '',
        size: '',
        gender: '',
        adopt: false,
    });

    const [loading, setLoading] = useState(true);

    // 🐶 반려견 정보 불러오기
    useEffect(() => {
        axios.get(`http://localhost:8080/api/pet/${petId}`, { withCredentials: true })
            .then((res) => {
                setPetData(res.data); // DTO 형태에 따라 조정
                setLoading(false);
            })
            .catch((err) => {
                console.error("반려견 정보 불러오기 실패", err);
                setLoading(false);
            });
    }, [petId]);

    // ✏️ 폼 핸들러
    const handleChange = (e) => {
        const { name, value, type, checked } = e.target;
        setPetData(prev => ({
            ...prev,
            [name]: type === 'checkbox' ? checked : value
        }));
    };

    // ✅ 제출 핸들러
    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            await axios.put(`http://localhost:8080/api/pet/edit/${petId}`, petData, {
                withCredentials: true
            });
            alert('수정 성공!');
            navigate('/mypet'); // 다시 프로필 목록으로
        } catch (err) {
            console.error('수정 실패', err);
            alert('수정 중 오류 발생');
        }
    };

    if (loading) return <p>로딩 중...</p>;

    return (
        <div className="edit-page">
            <h2>반려견 정보 수정</h2>
            <form onSubmit={handleSubmit}>
                <div>
                    <label>이름</label>
                    <input name="name" value={petData.name} onChange={handleChange} />
                </div>

                <div>
                    <label>품종</label>
                    <input name="type" value={petData.type} onChange={handleChange} />
                </div>

                <div>
                    <label>몸무게 (kg)</label>
                    <input type="number" name="weight" value={petData.weight} onChange={handleChange} />
                </div>

                <div>
                    <label>나이</label>
                    <input type="number" name="age" value={petData.age} onChange={handleChange} />
                </div>

                <div>
                    <label>크기</label>
                    <select name="size" value={petData.size} onChange={handleChange}>
                        <option value="SMALL">소형견</option>
                        <option value="MEDIUM">중형견</option>
                        <option value="LARGE">대형견</option>
                    </select>
                </div>

                <div>
                    <label>성별</label>
                    <select name="gender" value={petData.gender} onChange={handleChange}>
                        <option value="MALE">수컷</option>
                        <option value="FEMALE">암컷</option>
                        <option value="NEUTER">중성</option>
                    </select>
                </div>

                <div>
                    <label>입양 여부</label>
                    <input type="checkbox" name="adopt" checked={petData.adopt} onChange={handleChange} />
                </div>

                <button type="submit">저장</button>
            </form>
        </div>
    );
}

export default MyPetEditPage;
